import React, { useState, useEffect } from 'react';
import { MenuItem, MessageItem } from './types';
import Login from './pages/Login';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import MessageList from './components/MessageList';
import Footer from './components/Footer';

// --- Constants & Translations ---
const TRANSLATIONS = {
  pt: {
    loginTitle: "Acesse sua Conta",
    user: "Usuário",
    pass: "Senha",
    loginBtn: "Entrar",
    search: "Pesquisar",
    assign: "Atribuir",
    archive: "Arquivar",
    schedule: "Agendar",
    favorites: "Favoritas",
    logout: "Sair",
    empty: "Selecione uma pasta para ver as mensagens",
    noItems: "Nenhuma mensagem encontrada",
    theme: "Alternar Tema",
    lang: "Idioma",
    footer: "Redimensionável"
  },
  en: {
    loginTitle: "Access your Account",
    user: "User",
    pass: "Password",
    loginBtn: "Login",
    search: "Search",
    assign: "Assign",
    archive: "Archive",
    schedule: "Schedule",
    favorites: "Favorites",
    logout: "Logout",
    empty: "Select a folder to view messages",
    noItems: "No messages found",
    theme: "Toggle Theme",
    lang: "Language",
    footer: "Resizable"
  }
};

// --- API Services ---
const API_BASE = "https://my-json-server.typicode.com/EnkiGroup/DesafioFrontEnd2026Jr";

const App: React.FC = () => {
  // Global State
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [lang, setLang] = useState<'pt' | 'en'>('pt');
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Data State
  const [menus, setMenus] = useState<MenuItem[]>([]);
  const [selectedSubMenuId, setSelectedSubMenuId] = useState<number | null>(null);
  const [items, setItems] = useState<MessageItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  
  // UI State
  const [openMenus, setOpenMenus] = useState<Record<number, boolean>>({});
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);

  const t = TRANSLATIONS[lang];

  // --- Effects ---
  useEffect(() => {
    if (isLoggedIn) {
      fetch(`${API_BASE}/menus`)
        .then(res => res.json())
        .then(data => {
            if (Array.isArray(data)) {
              setMenus(data);
              if(data.length > 0) setOpenMenus({ [data[0].id]: true });
            }
        })
        .catch(err => console.error("Erro ao carregar menus:", err));
    }
  }, [isLoggedIn]);

  useEffect(() => {
    if (selectedSubMenuId !== null) {
      setLoading(true);
      fetch(`${API_BASE}/items/${selectedSubMenuId}`)
        .then(res => res.json())
        .then(data => {
          // Normalização: A API pode retornar um objeto único ou array
          // Também garantimos que cada item tenha os campos necessários para evitar erros de undefined
          const normalizedData = Array.isArray(data) ? data : (data && typeof data === 'object' ? [data] : []);
          
          const safeData = normalizedData.map((item: any) => ({
            ...item,
            id: item.id || Math.random(),
            users: Array.isArray(item.users) ? item.users : [] // Correção para o erro "map undefined"
          }));

          setItems(safeData);
          setLoading(false);
          setSelectedIds([]);
        })
        .catch(() => {
          setItems([]);
          setLoading(false);
        });
    }
  }, [selectedSubMenuId]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsUserMenuOpen(false);
  };

  const toggleMenu = (id: number) => {
    setOpenMenus(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const archiveSelected = () => {
    setItems(prev => prev.filter(item => !selectedIds.includes(item.id)));
    setSelectedIds([]);
  };

  // --- Components ---

  if (!isLoggedIn) {
    return (
      <Login 
        onLogin={handleLogin}
        lang={lang}
        theme={theme}
        setLang={setLang}
        setTheme={setTheme}
      />
    );
  }

  return (
    <div className={`h-screen flex flex-col overflow-hidden transition-colors duration-300 ${theme === 'dark' ? 'bg-slate-900 text-slate-100' : 'bg-white text-slate-800'}`}>
      
      {/* Header */}
      <Header 
        lang={lang}
        theme={theme}
        setLang={setLang}
        setTheme={setTheme}
        isSidebarOpen={isSidebarOpen}
        setIsSidebarOpen={setIsSidebarOpen}
        onLogout={handleLogout}
        isUserMenuOpen={isUserMenuOpen}
        setIsUserMenuOpen={setIsUserMenuOpen}
        logout={t.logout}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {/* Sidebar */}
        <Sidebar 
          menus={menus}
          selectedSubMenuId={selectedSubMenuId}
          setSelectedSubMenuId={setSelectedSubMenuId}
          openMenus={openMenus}
          toggleMenu={toggleMenu}
          theme={theme}
          isSidebarOpen={isSidebarOpen}
          setIsSidebarOpen={setIsSidebarOpen}
          favorites={t.favorites}
        />

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col overflow-hidden bg-white dark:bg-slate-900">
          
          {/* TopBar */}
          <TopBar 
            theme={theme}
            search={t.search}
            assign={t.assign}
            archive={t.archive}
            schedule={t.schedule}
            selectedIds={selectedIds}
            onArchive={archiveSelected}
          />

          {/* MessageList */}
          <MessageList 
            items={items}
            selectedIds={selectedIds}
            setSelectedIds={setSelectedIds}
            loading={loading}
            selectedSubMenuId={selectedSubMenuId}
            theme={theme}
            empty={t.empty}
            noItems={t.noItems}
          />

          {/* Footer */}
          <Footer 
            theme={theme}
            footer={t.footer}
          />
        </main>
      </div>
    </div>
  );
};

export default App;
